```perl
#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::API2::Resource::Font::CoreFont;
use PDF::Text::Simple;

# Function to extract metadata from the PDF
sub extract_metadata {
    my ($pdf) = @_;
    my $info = $pdf->info;
    return {
        Title => $info->Title,
        Author => $info->Author,
        Creator => $info->Creator,
        Producer => $info->Producer,
        ModDate => $info->ModDate->value,
        CreationDate => $info->CreationDate->value,
    };
}

# Function to extract tables from the PDF
sub extract_tables {
    my ($pdf) = @_;
    my $text = PDF::Text::Simple->new(
        pdf => $pdf,
        page => 1,  # Specify the page number to extract tables from
        margin => 10,
        width => 800,
    );
    $text->extract_tables;
    return $text->tables;
}

# Main script
my $filename = 'example.pdf';  # Specify your PDF filename here

# Load the PDF file
my $pdf = PDF::API2->open($filename);

# Extract metadata
my $metadata = extract_metadata($pdf);
print "Metadata:\n";
foreach my $key (keys %$metadata) {
    print "$key: $metadata->{$key}\n";
}

# Extract tables
my $tables = extract_tables($pdf);
print "Tables:\n";
foreach my $table (@$tables) {
    print "Table:\n";
    for my $row (@$table) {
        print join("\t", @$row), "\n";
    }
}
